@using sv_85ffc58fbb96444e8cd2cb9bc1639424.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Full Name</label>
                <input class="form-control" @bind="Reference.Name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="Reference.Relationship" placeholder="e.g., Former Manager" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Reference.Email" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" @bind="Reference.Phone" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

